import{_ as n,o as h,c as i,ag as o}from"./chunks/framework.BZohXCq9.js";const l=JSON.parse('{"title":"Mô Hình Kinh Doanh — Vivu Travel (giải thích đời thường)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/01-nen-tang-he-thong/00b-mo-hinh-kinh-doanh.md","filePath":"99-tham-khao/archive/01-nen-tang-he-thong/00b-mo-hinh-kinh-doanh.md"}'),a={name:"99-tham-khao/archive/01-nen-tang-he-thong/00b-mo-hinh-kinh-doanh.md"};function r(e,t,g,c,s,d){return h(),i("div",null,[...t[0]||(t[0]=[o(`<h1 id="mo-hinh-kinh-doanh-—-vivu-travel-giai-thich-đoi-thuong" tabindex="-1">Mô Hình Kinh Doanh — Vivu Travel (giải thích đời thường) <a class="header-anchor" href="#mo-hinh-kinh-doanh-—-vivu-travel-giai-thich-đoi-thuong" aria-label="Permalink to &quot;Mô Hình Kinh Doanh — Vivu Travel (giải thích đời thường)&quot;">​</a></h1><blockquote><p><strong>Phiên bản:</strong> 2.0 · <strong>Ngày:</strong> 26/05/2026 · <strong>Tier:</strong> 1 (Business)</p><p>File này trả lời <strong>7 câu cơ bản nhất</strong> về Vivu, viết theo kiểu mentor giảng cho người chưa startup bao giờ. Không cần học MBA mới đọc được.</p><p><strong>Quy tắc dùng:</strong> mỗi feature đề xuất trong sprint phải trả lời được &quot;phục vụ câu hỏi nào dưới đây?&quot;. Nếu không phục vụ câu nào → có thể là feature không tạo giá trị, dừng lại review.</p></blockquote><hr><h2 id="muc-luc-7-cau-hoi" tabindex="-1">Mục lục 7 câu hỏi <a class="header-anchor" href="#muc-luc-7-cau-hoi" aria-label="Permalink to &quot;Mục lục 7 câu hỏi&quot;">​</a></h2><ol><li><a href="#câu-1--vivu-bán-cái-gì">Vivu bán cái gì?</a></li><li><a href="#câu-2--bán-cho-ai">Bán cho ai?</a></li><li><a href="#câu-3--khách-tìm-thấy-vivu-bằng-cách-nào">Khách tìm thấy Vivu bằng cách nào?</a></li><li><a href="#câu-4--vivu-kiếm-tiền-thế-nào-bao-nhiêu">Vivu kiếm tiền thế nào? Bao nhiêu?</a></li><li><a href="#câu-5--tiền-chi-đi-đâu-hết">Tiền chi đi đâu hết?</a></li><li><a href="#câu-6--đối-thủ-là-ai-vivu-hơn-ở-đâu">Đối thủ là ai? Vivu hơn ở đâu?</a></li><li><a href="#câu-7--rủi-ro-lớn-nhất-là-gì-đo-lường-thế-nào-để-biết-vivu-đang-sống-tốt">Rủi ro lớn nhất là gì? Đo lường thế nào để biết Vivu đang sống tốt?</a></li></ol><hr><h2 id="cau-1-—-vivu-ban-cai-gi" tabindex="-1">Câu 1 — Vivu bán cái gì? <a class="header-anchor" href="#cau-1-—-vivu-ban-cai-gi" aria-label="Permalink to &quot;Câu 1 — Vivu bán cái gì?&quot;">​</a></h2><p><strong>Câu trả lời ngắn:</strong> Vivu bán <strong>tour du lịch trọn gói</strong> (tour package).</p><p><strong>Trọn gói nghĩa là sao?</strong> Khách trả 1 cục tiền, Vivu lo hết: xe đưa đón, khách sạn, ăn uống, hướng dẫn viên, vé tham quan. Khách không cần tự đặt từng cái.</p><p><strong>Ví dụ cụ thể:</strong></p><blockquote><p><em>&quot;Tour Đà Lạt 4 ngày 3 đêm, khởi hành 15/06/2026, giá 4.5 triệu/người. Bao gồm: xe khứ hồi Sài Gòn → Đà Lạt, khách sạn 3★, 3 bữa sáng + 4 bữa tối, vé Langbiang + Thung lũng tình yêu, hướng dẫn viên.&quot;</em></p></blockquote><p><strong>Vivu KHÔNG bán gì?</strong> (rất quan trọng để khỏi loãng)</p><ul><li>❌ Không bán <strong>khách sạn riêng lẻ</strong> (không cạnh tranh với Agoda, Booking.com). Hotel chỉ là một phần của tour package.</li><li>❌ Không bán <strong>vé máy bay rời</strong> (không cạnh tranh với Vietnam Airlines hay traveloka về vé).</li><li>❌ Không bán <strong>tour cho khách doanh nghiệp / công ty</strong> (B2B, MICE). Đây là thị trường khác, cần proposal riêng, không phù hợp tour chuẩn hoá.</li><li>❌ Không là <strong>trung gian</strong> cho bên khác bán tour (marketplace). Tour mà Vivu list trên web đều là <strong>tour của chính Vivu tự tổ chức</strong>.</li></ul><blockquote><p>💡 <strong>Vì sao gạch đầu dòng những cái KHÔNG bán?</strong> Vì startup chết nhiều nhất do &quot;thấy gì cũng làm, ai cũng phục vụ&quot;. Lock chặt phạm vi ngay từ đầu = giữ tỉnh táo về sau.</p></blockquote><hr><h2 id="cau-2-—-ban-cho-ai" tabindex="-1">Câu 2 — Bán cho ai? <a class="header-anchor" href="#cau-2-—-ban-cho-ai" aria-label="Permalink to &quot;Câu 2 — Bán cho ai?&quot;">​</a></h2><p><strong>Câu trả lời ngắn:</strong> Bán cho <strong>gia đình, cặp đôi, nhóm bạn người Việt</strong> trong độ tuổi 25-45, thu nhập trung-cao, muốn đi du lịch nghỉ dưỡng/khám phá trong nước.</p><p>Chi tiết 3 nhân vật cụ thể (gọi là <em>&quot;personas&quot;</em> — đại diện cho 3 nhóm khách điển hình): xem <a href="./00c-personas-user-journey"><code>00c-personas-user-journey.md</code></a>.</p><p><strong>Tại sao chọn đối tượng này?</strong></p><table tabindex="0"><thead><tr><th>Tiêu chí</th><th>Lý do chọn</th></tr></thead><tbody><tr><td><strong>Người Việt</strong> (không phải khách nước ngoài)</td><td>Vivu vận hành ở VN, hiểu insight khách Việt nhất. Khách Tây để Phase 1.5+</td></tr><tr><td><strong>25-45 tuổi</strong></td><td>Có thu nhập + có thời gian + chịu khó tìm online. Dưới 25t thường chưa có budget, trên 45t ít book online</td></tr><tr><td><strong>Thu nhập trung-cao</strong></td><td>Đủ tiền cho tour 3-15 triệu/người. Không cạnh tranh phân khúc rẻ nhất (backpacker tự đi)</td></tr><tr><td><strong>Đi gia đình / nhóm</strong> (không đi 1 mình)</td><td>Tour package value cao nhất khi đi nhóm 4-8 người. Solo traveler chiếm &lt;10%</td></tr></tbody></table><p><strong>KHÔNG bán cho ai?</strong></p><ul><li>❌ <strong>Khách doanh nghiệp</strong> (corporate, đoàn công ty 50+ người) — cần team sales B2B riêng, không phải MVP</li><li>❌ <strong>Backpacker</strong> đi tự túc — họ không mua tour package, chỉ search vé máy bay + hostel</li><li>❌ <strong>Khách quá trẻ (&lt;22t)</strong> — tour package không hợp budget của họ</li><li>❌ <strong>Khách quốc tế</strong> (Phase 1) — chỉ thêm Phase 1.5 khi có nguồn lực làm content EN</li></ul><hr><h2 id="cau-3-—-khach-tim-thay-vivu-bang-cach-nao" tabindex="-1">Câu 3 — Khách tìm thấy Vivu bằng cách nào? <a class="header-anchor" href="#cau-3-—-khach-tim-thay-vivu-bang-cach-nao" aria-label="Permalink to &quot;Câu 3 — Khách tìm thấy Vivu bằng cách nào?&quot;">​</a></h2><p>Đây gọi là <strong>&quot;kênh marketing&quot;</strong> — chỗ Vivu xuất hiện để khách biết tới.</p><table tabindex="0"><thead><tr><th>Kênh</th><th style="text-align:center;">Phase 1 (MVP)</th><th>Cách hoạt động</th></tr></thead><tbody><tr><td><strong>Google search</strong> (SEO)</td><td style="text-align:center;">✅ chính</td><td>Khách gõ &quot;tour Đà Nẵng 4 ngày gia đình&quot; → Google trả về kết quả → web Vivu nằm top → khách click vào</td></tr><tr><td><strong>Quảng cáo Google</strong> (Google Ads)</td><td style="text-align:center;">✅ phụ</td><td>Vivu trả tiền Google → khi khách search keyword liên quan, web Vivu hiện trước (có chữ &quot;Quảng cáo&quot;)</td></tr><tr><td><strong>Email</strong></td><td style="text-align:center;">✅</td><td>Sau khi khách book lần đầu → email confirm + sau này gửi tour mới</td></tr><tr><td><strong>Facebook / Instagram</strong></td><td style="text-align:center;">🔶 nice-to-have</td><td>Đăng bài content du lịch, làm brand awareness</td></tr><tr><td><strong>TikTok / KOL</strong></td><td style="text-align:center;">❌ Phase 2</td><td>Người nổi tiếng review tour → ăn hoa hồng</td></tr><tr><td><strong>Affiliate</strong></td><td style="text-align:center;">❌ Phase 2</td><td>Bên thứ 3 share link Vivu, ai book qua link → bên đó ăn %</td></tr></tbody></table><p><strong>Vì sao Vivu chọn Google search (SEO) làm kênh chính?</strong></p><ul><li>Khách book tour không quyết định <strong>ngay tức thì</strong> như mua quần áo. Họ thường <strong>search Google trước</strong>, đọc 5-10 trang web, so sánh 3-4 tour rồi mới quyết. → Ai xuất hiện top Google = chiếm tay khách.</li><li><strong>SEO miễn phí</strong> sau khi build (so với Google Ads phải trả tiền mỗi click). Đầu tư công sức làm content + tối ưu kỹ thuật → kết quả tích luỹ 12-18 tháng. Đây là <strong>lợi thế lâu dài</strong> mà đối thủ copy không dễ.</li><li><strong>Khách qua Google đã có ý định mua</strong> (gõ keyword &quot;tour&quot; = đang cần tour). Conversion cao hơn social organic nhiều lần.</li></ul><p><strong>Trade-off của SEO:</strong> chậm 6-12 tháng mới ra kết quả. Trong lúc đó phải dùng Google Ads (trả tiền) để có khách ngay.</p><blockquote><p>💡 <strong>Một câu chốt cho team dev:</strong> mọi page tour / điểm đến / hotel phải tối ưu SEO ngay từ ngày 1. Không &quot;làm tạm rồi sửa SEO sau&quot; — vì Google index cần thời gian, sửa muộn = mất 3-6 tháng.</p></blockquote><hr><h2 id="cau-4-—-vivu-kiem-tien-the-nao-bao-nhieu" tabindex="-1">Câu 4 — Vivu kiếm tiền thế nào? Bao nhiêu? <a class="header-anchor" href="#cau-4-—-vivu-kiem-tien-the-nao-bao-nhieu" aria-label="Permalink to &quot;Câu 4 — Vivu kiếm tiền thế nào? Bao nhiêu?&quot;">​</a></h2><p><strong>Câu trả lời ngắn:</strong> Vivu mua dịch vụ (hotel + xe + guide + ăn) với giá sỉ → đóng gói thành tour → bán cho khách với giá cao hơn → ăn chênh lệch.</p><h3 id="_4-1-cach-kiem-tien-revenue-model" tabindex="-1">4.1 Cách kiếm tiền (Revenue model) <a class="header-anchor" href="#_4-1-cach-kiem-tien-revenue-model" aria-label="Permalink to &quot;4.1 Cách kiếm tiền (Revenue model)&quot;">​</a></h3><p>Tiếng tây gọi cách này là <strong>&quot;markup&quot;</strong> — nghĩa là &quot;đánh dấu giá lên&quot;. Đời thường gọi là &quot;ăn chênh lệch&quot;.</p><p><strong>Ví dụ minh hoạ (số giả định):</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tour Đà Lạt 4N3Đ — 1 khách</span></span>
<span class="line"><span></span></span>
<span class="line"><span>GIÁ VỐN (tiền Vivu chi ra):</span></span>
<span class="line"><span>  Khách sạn 3 đêm          : 1.500.000đ</span></span>
<span class="line"><span>  Xe khứ hồi (chia theo đầu): 1.200.000đ</span></span>
<span class="line"><span>  Ăn uống (4 bữa sáng+tối) :   600.000đ</span></span>
<span class="line"><span>  Vé tham quan               :  300.000đ</span></span>
<span class="line"><span>  Hướng dẫn viên (chia)      :  200.000đ</span></span>
<span class="line"><span>  Tổng giá vốn               : 3.800.000đ</span></span>
<span class="line"><span></span></span>
<span class="line"><span>GIÁ BÁN cho khách           : 4.500.000đ</span></span>
<span class="line"><span>                              ─────────</span></span>
<span class="line"><span>TIỀN CHÊNH LỆCH (markup)    :   700.000đ  ← khoảng 15% giá bán</span></span></code></pre></div><p><strong>Trong 700.000đ &quot;chênh lệch&quot; này còn phải trừ:</strong></p><ul><li>Phí thanh toán VNPay/MoMo (~1.5% giá bán) ≈ 67.500đ</li><li>Dự phòng hoàn huỷ, sự cố (~1-2% giá bán) ≈ 67.500đ</li><li>Chi phí cố định phân bổ (lương team, marketing, hosting) → cái này phụ thuộc số đơn/tháng</li></ul><p><strong>Số khách càng nhiều, chi phí cố định chia đều ra càng thấp.</strong> Đây là lý do startup luôn muốn &quot;scale&quot; — bán nhiều hơn để mỗi đơn lãi nhiều hơn.</p><h3 id="_4-2-doanh-thu-vs-loi-nhuan-—-đung-nham" tabindex="-1">4.2 Doanh thu vs Lợi nhuận — đừng nhầm <a class="header-anchor" href="#_4-2-doanh-thu-vs-loi-nhuan-—-đung-nham" aria-label="Permalink to &quot;4.2 Doanh thu vs Lợi nhuận — đừng nhầm&quot;">​</a></h3><p>Đây là 2 con số khác nhau, hay bị nhầm:</p><table tabindex="0"><thead><tr><th>Khái niệm</th><th>Đời thường</th><th>Ví dụ với tour trên</th></tr></thead><tbody><tr><td><strong>Doanh thu</strong></td><td>Tổng tiền khách trả</td><td>4.500.000đ</td></tr><tr><td><strong>Giá vốn</strong></td><td>Tiền chi ra để cung cấp tour</td><td>3.800.000đ</td></tr><tr><td><strong>Lợi nhuận gộp</strong></td><td>Doanh thu − Giá vốn (chưa trừ chi phí khác)</td><td>700.000đ</td></tr><tr><td><strong>Lợi nhuận thực</strong></td><td>Lợi nhuận gộp − Chi phí marketing − Lương − Phí thanh toán − Thuế</td><td>Có thể chỉ còn 100-300k, hoặc thậm chí âm nếu tháng ít đơn</td></tr></tbody></table><blockquote><p>💡 <strong>Đầu năm 1-2 thường lỗ là chuyện bình thường.</strong> Startup chấp nhận lỗ ngắn hạn để xây brand + tích SEO authority + có user base. Lãi xuất hiện khi đạt <strong>break-even</strong> = lúc tổng lợi nhuận gộp vừa đủ trả tổng chi phí cố định.</p></blockquote><h3 id="_4-3-cac-nguon-thu-phu-phase-1-5-tro-đi" tabindex="-1">4.3 Các nguồn thu phụ (Phase 1.5 trở đi) <a class="header-anchor" href="#_4-3-cac-nguon-thu-phu-phase-1-5-tro-đi" aria-label="Permalink to &quot;4.3 Các nguồn thu phụ (Phase 1.5 trở đi)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Nguồn</th><th>Phase</th><th>Cách hoạt động</th></tr></thead><tbody><tr><td><strong>Bán bảo hiểm du lịch</strong></td><td>1.5</td><td>Khi khách book tour, hỏi &quot;mua thêm bảo hiểm 50k/người không?&quot; → Vivu ăn hoa hồng từ hãng bảo hiểm</td></tr><tr><td><strong>Dịch vụ thêm</strong></td><td>1.5</td><td>Đưa đón sân bay riêng, room upgrade, tour mở rộng</td></tr><tr><td><strong>Voucher / gift card</strong></td><td>1.5</td><td>Khách mua voucher trước (tiền vô túi Vivu sớm), tặng người khác</td></tr><tr><td><strong>KOL / Affiliate</strong></td><td>2</td><td>Người nổi tiếng share link, ai book qua link → KOL ăn 5-10%</td></tr></tbody></table><hr><h2 id="cau-5-—-tien-chi-đi-đau-het" tabindex="-1">Câu 5 — Tiền chi đi đâu hết? <a class="header-anchor" href="#cau-5-—-tien-chi-đi-đau-het" aria-label="Permalink to &quot;Câu 5 — Tiền chi đi đâu hết?&quot;">​</a></h2><p>Hai loại chi phí cần phân biệt:</p><h3 id="_5-1-chi-phi-bien-đoi-—-chi-theo-tung-tour-ban-đuoc" tabindex="-1">5.1 Chi phí biến đổi — chi theo từng tour bán được <a class="header-anchor" href="#_5-1-chi-phi-bien-đoi-—-chi-theo-tung-tour-ban-đuoc" aria-label="Permalink to &quot;5.1 Chi phí biến đổi — chi theo từng tour bán được&quot;">​</a></h3><p><strong>(Bán 1 tour mới chi 1 lần. Không bán không chi.)</strong></p><table tabindex="0"><thead><tr><th>Khoản</th><th>Ước tính % giá bán</th></tr></thead><tbody><tr><td>Khách sạn (allotment đã ký với hotel)</td><td>30-40%</td></tr><tr><td>Xe / phương tiện</td><td>20-30%</td></tr><tr><td>Ăn uống + vé tham quan + guide</td><td>15-25%</td></tr><tr><td>Phí thanh toán VNPay/MoMo</td><td>1.5-2%</td></tr><tr><td>Dự phòng hoàn huỷ</td><td>1-2%</td></tr><tr><td><strong>Tổng cộng</strong></td><td><strong>~70-90% giá bán</strong></td></tr><tr><td><strong>Lợi nhuận gộp còn lại</strong></td><td><strong>~10-30% giá bán</strong></td></tr></tbody></table><h3 id="_5-2-chi-phi-co-đinh-—-chi-đeu-moi-thang-du-ban-nhieu-hay-it" tabindex="-1">5.2 Chi phí cố định — chi đều mỗi tháng dù bán nhiều hay ít <a class="header-anchor" href="#_5-2-chi-phi-co-đinh-—-chi-đeu-moi-thang-du-ban-nhieu-hay-it" aria-label="Permalink to &quot;5.2 Chi phí cố định — chi đều mỗi tháng dù bán nhiều hay ít&quot;">​</a></h3><p><strong>(Tháng nào cũng phải trả, bán 0 đơn hay 1000 đơn cũng vậy.)</strong></p><table tabindex="0"><thead><tr><th>Khoản</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Lương team</strong> (3-5 người ban đầu)</td><td>Khoản lớn nhất</td></tr><tr><td><strong>Marketing</strong> (làm SEO content + Google Ads)</td><td>Tăng dần khi mở rộng</td></tr><tr><td><strong>Hosting + dịch vụ</strong> (Supabase + Vercel + Cloudinary + email)</td><td>Phase 1 dùng free tier nhiều, gần như 0đ</td></tr><tr><td><strong>Văn phòng</strong> (nếu có)</td><td>Tuỳ chính sách, có thể work-from-home tiết kiệm</td></tr><tr><td><strong>Pháp lý + kế toán</strong></td><td>Báo cáo thuế hằng quý, contract</td></tr></tbody></table><blockquote><p>💡 <strong>Mục tiêu Phase 1:</strong> giảm chi phí cố định càng thấp càng tốt (work remote, tận dụng free tier dịch vụ) → kéo dài runway. Runway là <strong>số tháng tiền còn lại trước khi cạn vốn</strong>. Runway dài = có thời gian thử nghiệm + sửa sai.</p></blockquote><hr><h2 id="cau-6-—-đoi-thu-la-ai-vivu-hon-o-đau" tabindex="-1">Câu 6 — Đối thủ là ai? Vivu hơn ở đâu? <a class="header-anchor" href="#cau-6-—-đoi-thu-la-ai-vivu-hon-o-đau" aria-label="Permalink to &quot;Câu 6 — Đối thủ là ai? Vivu hơn ở đâu?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Đối thủ</th><th>Họ mạnh ở</th><th>Họ yếu ở</th><th>Vivu hơn ở chỗ</th></tr></thead><tbody><tr><td><strong>Vietravel, Saigontourist</strong> (tour operator lớn)</td><td>Brand uy tín nhiều năm, có chi nhánh vật lý, inventory tour rộng</td><td>Website cũ, UX kém, khó book online, ít tối ưu mobile</td><td>Web hiện đại, mobile-first, booking flow ít bước, SEO mạnh</td></tr><tr><td><strong>Klook, Traveloka</strong> (sàn quốc tế)</td><td>App ngon, đa quốc gia, brand quốc tế</td><td>Thiếu tour local VN đặc trưng, EN-first nên không quá Việt hoá</td><td>Tour local tinh hoa (homestay vùng cao, foodtour), tiếng Việt thuần</td></tr><tr><td><strong>Operator nhỏ trên Facebook</strong></td><td>Linh hoạt, giá rẻ, gần gũi khách</td><td>Không minh bạch giá, không có review độc lập, chuyển khoản tay rủi ro</td><td>Giá hiển thị công khai, review verified, payment chính thống có hoá đơn</td></tr><tr><td><strong>Booking.com, Agoda</strong></td><td>Inventory hotel khổng lồ</td><td>Không có tour package</td><td>Vivu bán <em>tour</em> (gói trọn), khác category hẳn — không cạnh tranh trực tiếp</td></tr></tbody></table><p><strong>Định vị Vivu trong 1 câu:</strong></p><blockquote><p><em>&quot;Vietravel của thế hệ web hiện đại — tour curate cẩn thận, web đẹp, book mobile mượt, SEO mạnh, làm cho người Việt.&quot;</em></p></blockquote><p><strong>Cạnh tranh sống còn:</strong> đối thủ trực tiếp nhất là <strong>Vietravel / Saigontourist</strong> nếu họ rebuild web. Nhưng họ là công ty lớn, di chuyển chậm — Vivu có lợi thế &quot;small + fast&quot; trong 2-3 năm đầu.</p><hr><h2 id="cau-7-—-rui-ro-lon-nhat-la-gi-đo-luong-the-nao-đe-biet-vivu-đang-song-tot" tabindex="-1">Câu 7 — Rủi ro lớn nhất là gì? Đo lường thế nào để biết Vivu đang sống tốt? <a class="header-anchor" href="#cau-7-—-rui-ro-lon-nhat-la-gi-đo-luong-the-nao-đe-biet-vivu-đang-song-tot" aria-label="Permalink to &quot;Câu 7 — Rủi ro lớn nhất là gì? Đo lường thế nào để biết Vivu đang sống tốt?&quot;">​</a></h2><h3 id="_7-1-cac-rui-ro-can-đe-mat" tabindex="-1">7.1 Các rủi ro cần để mắt <a class="header-anchor" href="#_7-1-cac-rui-ro-can-đe-mat" aria-label="Permalink to &quot;7.1 Các rủi ro cần để mắt&quot;">​</a></h3><p>Xếp theo mức độ nguy hiểm:</p><table tabindex="0"><thead><tr><th>Rủi ro</th><th>Mức độ</th><th>Cách giảm thiểu</th></tr></thead><tbody><tr><td><strong>Không đủ tour để bán</strong> (chưa ký được đủ partner hotel/xe)</td><td>🔴 CAO</td><td>Founder phụ trách ký contract trước launch. Target 20-30 tour cho Phase 1</td></tr><tr><td><strong>SEO mất 6-12 tháng mới ra kết quả</strong></td><td>🔴 CAO</td><td>Phase 1 chấp nhận trả tiền Google Ads bù. Đồng thời invest content nặng tay</td></tr><tr><td><strong>Tỉ lệ khách book / khách vô web quá thấp</strong> (gọi là <em>conversion rate</em> thấp)</td><td>🟠 TRUNG BÌNH</td><td>A/B test booking flow Phase 1.5, gắn analytics ngay</td></tr><tr><td><strong>Thanh toán VNPay/MoMo bị lỗi timeout</strong></td><td>🟠 TRUNG BÌNH</td><td>Có cơ chế retry, lưu trạng thái PENDING, manual recovery</td></tr><tr><td><strong>Hotel partner đột ngột không giữ phòng</strong></td><td>🟠 TRUNG BÌNH</td><td>Mỗi điểm đến có ≥2 hotel backup cùng tầm</td></tr><tr><td><strong>2 khách book trùng slot cuối cùng → overbook</strong></td><td>🟡 THẤP-TRUNG</td><td>Đã có code lock database (xem <a href="./08-chien-luoc-concurrency"><code>08-chien-luoc-concurrency.md</code></a>)</td></tr><tr><td><strong>Luật bảo vệ dữ liệu cá nhân VN siết</strong></td><td>🟡 THẤP</td><td>Phase 1.5 review compliance, hiện chỉ thu data tối thiểu</td></tr></tbody></table><h3 id="_7-2-cac-chi-so-song-con-can-theo-doi" tabindex="-1">7.2 Các chỉ số sống còn cần theo dõi <a class="header-anchor" href="#_7-2-cac-chi-so-song-con-can-theo-doi" aria-label="Permalink to &quot;7.2 Các chỉ số sống còn cần theo dõi&quot;">​</a></h3><p>Đây gọi là <strong>KPI</strong> (Key Performance Indicators — chỉ số đo hiệu quả). Mỗi tháng cần biết:</p><table tabindex="0"><thead><tr><th>Chỉ số</th><th>Định nghĩa đời thường</th><th>Mục tiêu Phase 1</th></tr></thead><tbody><tr><td><strong>Số booking thành công / tháng</strong></td><td>Bao nhiêu khách book + trả tiền xong</td><td>Tăng đều mỗi tháng</td></tr><tr><td><strong>Trung bình mỗi đơn bao nhiêu tiền</strong></td><td>Tổng doanh thu ÷ số booking</td><td>5-8 triệu/đơn</td></tr><tr><td><strong>Tỉ lệ khách vào web → khách book</strong></td><td>(số booking ÷ số khách unique vào web) × 100%</td><td>&gt;0.5% là OK, &gt;1% là tốt</td></tr><tr><td><strong>Tốn bao nhiêu marketing để có 1 khách</strong></td><td>Chi phí marketing tháng ÷ số khách mới</td><td>&lt;15% trung bình mỗi đơn</td></tr><tr><td><strong>Tỉ lệ khách quay lại đặt lần 2</strong></td><td>(Khách book lần 2+ ÷ tổng khách) × 100%</td><td>&gt;20% sau 12 tháng</td></tr><tr><td><strong>Traffic SEO organic</strong></td><td>Số khách vào web từ Google không qua quảng cáo</td><td>Tăng đều mỗi tháng (lag 6-12 tháng)</td></tr><tr><td><strong>Lỗi thanh toán / tổng booking</strong></td><td>Tỉ lệ booking PENDING không lên PAID</td><td>&lt;2%</td></tr></tbody></table><blockquote><p>💡 <strong>Đầu Phase 1, các con số này còn ít data → đặt mục tiêu thấp, review hằng tháng, điều chỉnh.</strong> Đừng đo &quot;stress&quot; vì 1 tháng không đạt — pattern 3 tháng liên tiếp mới có ý nghĩa.</p></blockquote><hr><h2 id="tom-tat-1-trang-cho-ban-dan-len-tuong" tabindex="-1">Tóm tắt 1 trang (cho bạn dán lên tường) <a class="header-anchor" href="#tom-tat-1-trang-cho-ban-dan-len-tuong" aria-label="Permalink to &quot;Tóm tắt 1 trang (cho bạn dán lên tường)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ VIVU TRAVEL — MÔ HÌNH KINH DOANH (1 trang)                      │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│ BÁN GÌ?    Tour du lịch trọn gói (Vivu tự tổ chức, không sàn)  │</span></span>
<span class="line"><span>│ CHO AI?    Gia đình + cặp đôi + nhóm bạn Việt 25-45, thu nhập   │</span></span>
<span class="line"><span>│            trung-cao, đi du lịch nội địa                        │</span></span>
<span class="line"><span>│ TÌM Ở ĐÂU? Google Search (SEO) là chính, Google Ads phụ         │</span></span>
<span class="line"><span>│ ĂN TIỀN?   Chênh lệch giá vốn ↔ giá bán (markup 15-25%)         │</span></span>
<span class="line"><span>│ CHI ĐÂU?   Hotel/xe/guide/ăn (~70-90% giá bán) + lương team +   │</span></span>
<span class="line"><span>│            marketing + hosting                                  │</span></span>
<span class="line"><span>│ ĐỐI THỦ?   Vietravel/Saigontourist (web cũ), Klook (không local)│</span></span>
<span class="line"><span>│ ĐO LƯỜNG?  Booking/tháng + Conversion + Repeat rate + SEO traffic│</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><hr><h2 id="muc-tieu-cu-the-phase-1-placeholder-—-team-fill-sau-khi-co-data" tabindex="-1">Mục tiêu cụ thể Phase 1 (placeholder — team fill sau khi có data) <a class="header-anchor" href="#muc-tieu-cu-the-phase-1-placeholder-—-team-fill-sau-khi-co-data" aria-label="Permalink to &quot;Mục tiêu cụ thể Phase 1 (placeholder — team fill sau khi có data)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Đến hết Q3/2026 (6 tháng sau launch):</span></span>
<span class="line"><span>[ ] Có ___ tour active trên web              (đề xuất: 20-30)</span></span>
<span class="line"><span>[ ] Đạt ___ booking thành công/tháng         (đề xuất: tháng 6 = 50)</span></span>
<span class="line"><span>[ ] Trung bình mỗi đơn ___ VND               (đề xuất: 5-8 triệu)</span></span>
<span class="line"><span>[ ] Conversion rate ___ %                    (đề xuất: &gt;0.5%)</span></span>
<span class="line"><span>[ ] SEO organic traffic ___ unique/tháng     (đề xuất: tháng 6 = 5.000)</span></span>
<span class="line"><span>[ ] Repeat rate sau 6 tháng ___ %            (đề xuất: &gt;10%)</span></span></code></pre></div><hr><h2 id="phu-luc-—-mini-tu-đien-thuat-ngu-trong-file-nay" tabindex="-1">Phụ lục — Mini từ điển thuật ngữ trong file này <a class="header-anchor" href="#phu-luc-—-mini-tu-đien-thuat-ngu-trong-file-nay" aria-label="Permalink to &quot;Phụ lục — Mini từ điển thuật ngữ trong file này&quot;">​</a></h2><p>(Thuật ngữ gặp thường xuyên trong tài liệu kinh doanh)</p><table tabindex="0"><thead><tr><th>Thuật ngữ tiếng Anh</th><th>Tiếng Việt đời thường</th></tr></thead><tbody><tr><td><strong>Markup</strong></td><td>Tiền chênh lệch (giá bán − giá vốn)</td></tr><tr><td><strong>Revenue (doanh thu)</strong></td><td>Tổng tiền khách trả</td></tr><tr><td><strong>Gross profit (lợi nhuận gộp)</strong></td><td>Doanh thu − Giá vốn</td></tr><tr><td><strong>Net profit (lợi nhuận thực)</strong></td><td>Doanh thu − Tất cả chi phí (kể cả lương + marketing)</td></tr><tr><td><strong>Variable cost (chi phí biến đổi)</strong></td><td>Chi phí phát sinh theo từng đơn bán</td></tr><tr><td><strong>Fixed cost (chi phí cố định)</strong></td><td>Chi phí trả đều mỗi tháng dù bán nhiều hay ít</td></tr><tr><td><strong>Break-even</strong></td><td>Điểm hoà vốn — lợi nhuận gộp = chi phí cố định</td></tr><tr><td><strong>Runway</strong></td><td>Số tháng tiền còn lại trước khi cạn vốn</td></tr><tr><td><strong>CAC</strong> (Customer Acquisition Cost)</td><td>Tốn bao nhiêu marketing để có 1 khách mới</td></tr><tr><td><strong>AOV</strong> (Average Order Value)</td><td>Trung bình mỗi đơn khách chi bao nhiêu</td></tr><tr><td><strong>Conversion rate</strong></td><td>Tỉ lệ khách vào web → khách book</td></tr><tr><td><strong>Repeat rate</strong></td><td>Tỉ lệ khách book lại lần 2+</td></tr><tr><td><strong>KPI</strong></td><td>Chỉ số đo hiệu quả (Key Performance Indicator)</td></tr><tr><td><strong>SEO</strong></td><td>Tối ưu công cụ tìm kiếm (làm web hiện top Google miễn phí)</td></tr><tr><td><strong>B2C</strong></td><td>Bán trực tiếp cho khách lẻ (Business-to-Consumer)</td></tr><tr><td><strong>B2B</strong></td><td>Bán cho doanh nghiệp (Business-to-Business)</td></tr><tr><td><strong>MVP</strong></td><td>Phiên bản tối thiểu khả thi (Minimum Viable Product)</td></tr></tbody></table><blockquote><p>💡 <strong>Cách dùng từ điển:</strong> khi gặp thuật ngữ này trong file khác, quay lại đây xem. File sẽ được mở rộng thành <code>99-tu-dien-thuat-ngu.md</code> riêng khi nhiều file dùng chung.</p></blockquote><hr><h2 id="mapping-ve-anchor-decisions-trong-vision" tabindex="-1">Mapping về Anchor decisions trong Vision <a class="header-anchor" href="#mapping-ve-anchor-decisions-trong-vision" aria-label="Permalink to &quot;Mapping về Anchor decisions trong Vision&quot;">​</a></h2><p>Mỗi câu hỏi ở trên trace về anchor V-01 → V-07 trong <a href="./00-tam-nhin"><code>00-tam-nhin.md</code></a>:</p><table tabindex="0"><thead><tr><th>Câu</th><th>Trace tới</th></tr></thead><tbody><tr><td>Câu 1 (Bán cái gì)</td><td>V-01 (MVP tour-only) + V-02 (B2C direct) + V-05 (Hotel content-only)</td></tr><tr><td>Câu 2 (Bán cho ai)</td><td>V-01 (B2C) + WHO trong Vision Phần 2</td></tr><tr><td>Câu 3 (Tìm Vivu đâu)</td><td>V-03 (SEO-first)</td></tr><tr><td>Câu 4 (Kiếm tiền)</td><td>V-02 (B2C direct markup, không commission) + V-07 (Phase 2 mở upsell)</td></tr><tr><td>Câu 5 (Chi đâu)</td><td>(operational — không trực tiếp map technical)</td></tr><tr><td>Câu 6 (Đối thủ)</td><td>V-02 + Non-Goals trong Vision</td></tr><tr><td>Câu 7 (Rủi ro + KPI)</td><td>V-04 (Must login → loyalty) + V-06 (Team 2-3 dev — cần tự động hoá KPI)</td></tr></tbody></table><hr><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ngày</th><th>Version</th><th>Thay đổi</th></tr></thead><tbody><tr><td>26/05/2026</td><td>1.0</td><td>Khởi tạo BMC chuẩn 9 ô + Unit economics framework (jargon nặng)</td></tr><tr><td>26/05/2026</td><td>2.0</td><td><strong>Rewrite plain language.</strong> Bỏ BMC framework, thay bằng 7 câu hỏi đời thường. Thêm ví dụ số cụ thể, mini glossary, tóm tắt 1 trang. Bản v1.0 archive trong git history.</td></tr></tbody></table><hr><p><em>File này thuộc <strong>Tier 1 (Business)</strong>. References:</em></p><ul><li><em>Vision: <a href="./00-tam-nhin"><code>00-tam-nhin.md</code></a></em></li><li><em>Personas chi tiết: <a href="./00c-personas-user-journey"><code>00c-personas-user-journey.md</code></a></em></li><li><em>Chiến lược triển khai: <a href="./01-chien-luoc-tong-the"><code>01-chien-luoc-tong-the.md</code></a></em></li></ul>`,92)])])}const p=n(a,[["render",r]]);export{l as __pageData,p as default};
